var get = function get(obj, str) {
  // dot notation string -> array of keys
  var keys = str.split('.'); // length of keys array

  var len = keys.length; // loop through keys updating the reference to child objects

  var current = obj;
  var name;

  for (var index = 0; index < len; index++) {
    // current key name
    name = keys[index]; // stop searching if a child object is missing

    if (!current[name]) {
      return;
    }

    current = current[name];
  }

  return current;
};
